// Extract orderId from payment webhook data
const webhookData = $input.item.json;

console.log('=== DEBUG: Full webhook data ===');
console.log(JSON.stringify(webhookData, null, 2));

let orderId = null;

// Try multiple paths
if (webhookData.data?.metadata?.orderId) {
  orderId = webhookData.data.metadata.orderId;
  console.log('Found orderId in data.metadata.orderId:', orderId);
}
else if (webhookData.metadata?.orderId) {
  orderId = webhookData.metadata.orderId;
  console.log('Found orderId in metadata.orderId:', orderId);
}
else if (webhookData.body?.data?.metadata?.orderId) {
  orderId = webhookData.body.data.metadata.orderId;
  console.log('Found orderId in body.data.metadata.orderId:', orderId);
}
else if (webhookData.orderId) {
  orderId = webhookData.orderId;
  console.log('Found orderId directly:', orderId);
}

if (!orderId) {
  console.error('=== ERROR: No orderId found ===');
  console.error('Available keys:', Object.keys(webhookData));
  throw new Error('No orderId found in payment webhook data. Check logs for structure.');
}

console.log('=== SUCCESS: OrderID extracted ===');
console.log('OrderID:', orderId);

const paymentData = webhookData.data || webhookData;

return {
  json: {
    orderId: orderId,
    paymentId: paymentData.id || 'unknown',
    paymentStatus: paymentData.status || 'unknown',
    amount: paymentData.amount || 0,
    currency: paymentData.currency || 'ISK',
    paymentDate: new Date().toISOString(),
    rawData: webhookData
  }
};

// Extract file ID from Google Drive API response
const files = $json.files || [];

if (files.length === 0) {
  const orderId = $node["Extract OrderID from Payment"].json.orderId;
  throw new Error(`Questionnaire sheet not found for orderId: ${orderId}`);
}

// Return the first file's data
return {
  json: {
    spreadsheetId: files[0].id,
    name: files[0].name,
    mimeType: files[0].mimeType
  }
};

// Read sheet data from HTTP response
const response = $json;

console.log('=== Parse Sheet Data ===');
console.log('Response:', JSON.stringify(response, null, 2));

// Extract values array (first row of data)
const values = response.values || [];

if (values.length === 0 || values[0].length === 0) {
  throw new Error('No data found in sheet');
}

const row = values[0];

// Map array to object (orderId, timestamp, companyName, email, name, formData)
const orderId = row[0];
const timestamp = row[1];
const companyName = row[2];
const email = row[3];
const name = row[4];
const formDataJson = row[5];

// Parse formData JSON string
let formData;
try {
  formData = JSON.parse(formDataJson);
  console.log('✅ FormData parsed successfully');
} catch (parseError) {
  console.error('FormData parse error:', parseError.message);
  throw new Error('Failed to parse formData: ' + parseError.message);
}

// Get spreadsheet ID for moving later
const spreadsheetId = $node["Extract Spreadsheet ID"].json.spreadsheetId;

// Return parsed questionnaire data
return {
  json: {
    orderId: orderId,
    timestamp: timestamp,
    companyName: companyName,
    email: email,
    name: name,
    formData: formData,
    fileId: spreadsheetId
  }
};

// Get questionnaire data (already parsed by Parse Sheet Data node)
const questionnaireData = $node["Parse Sheet Data"].json;

// Get payment data
const paymentData = $node["Extract OrderID from Payment"].json;

// Merge data
return {
  json: {
    orderId: questionnaireData.orderId,
    timestamp: questionnaireData.timestamp,
    companyName: questionnaireData.companyName,
    email: questionnaireData.email,
    name: questionnaireData.name,
    formData: questionnaireData.formData,
    paymentId: paymentData.paymentId,
    paymentStatus: paymentData.paymentStatus,
    amount: paymentData.amount,
    currency: paymentData.currency,
    paymentDate: paymentData.paymentDate
  }
};

// With Append mode, $input.all() gives us array of both items
const items = $input.all();

console.log('Total items:', items.length);

let part1 = '';
let part2 = '';

// Process each item from the merge
for (let i = 0; i < items.length; i++) {
  const item = items[i].json;
  console.log(`Item ${i}:`, Object.keys(item));

  // The output from AI Agent is in .output or .text
  const output = item.output || item.text || '';

  console.log(`Item ${i} output length:`, output.length);
  console.log(`Item ${i} output preview:`, output.substring(0, 100));

  // Determine which part this is
  if (output.includes('EXECUTIVE SUMMARY') || output.includes('Tækifæri #1')) {
    part1 = output;
    console.log(`Item ${i} is Part 1 (Opportunities)`);
  } else if (output.includes('30 DAGA') || output.includes('VIKA 1') || output.includes('30 Daga')) {
    part2 = output;
    console.log(`Item ${i} is Part 2 (Implementation)`);
  }
}

// Combine
const completeRoadmap = part1 + '\n\n---\n\n' + part2;

console.log('Part 1 length:', part1.length);
console.log('Part 2 length:', part2.length);
console.log('Complete roadmap length:', completeRoadmap.length);

return {
  json: {
    roadmap: completeRoadmap,
    part1Length: part1.length,
    part2Length: part2.length,
    totalLength: completeRoadmap.length
  }
};

// The roadmap is already merged and ready from Combine Text
const roadmap = $json.roadmap;

// Get metadata from Merge Payment + Questionnaire node
const orderId = $node["Merge Payment + Questionnaire"].json.orderId;
const companyName = $node["Merge Payment + Questionnaire"].json.companyName;
const email = $node["Merge Payment + Questionnaire"].json.email;
const name = $node["Merge Payment + Questionnaire"].json.name;

return {
  json: {
    orderId,
    companyName,
    email,
    name,
    roadmap,
    generatedAt: new Date().toISOString()
  }
};

const roadmap = $input.item.json.roadmap;
const orderId = $input.item.json.orderId;
const companyName = $input.item.json.companyName;

// Convert roadmap text to binary
const binaryData = Buffer.from(roadmap, 'utf-8');

return {
  json: {
    orderId: orderId,
    companyName: companyName,
    roadmap: roadmap
  },
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'text/markdown',
      fileName: `${orderId}-${companyName}.md`
    }
  }
};

const formData = $input.item.json.body;

// Generate unique order ID
const timestamp = new Date().toISOString();
const orderId = `AI-${timestamp.slice(0,10)}-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;

// Extract key fields
const companyName = formData.companyName || 'Unknown Company';
const email = formData.email || 'no-email@example.com';
const name = formData.name || 'Unknown';

// Return data for Google Sheets
return {
  json: {
    orderId: orderId,
    timestamp: timestamp,
    companyName: companyName,
    email: email,
    name: name,
    formData: formData,
    formDataJson: JSON.stringify(formData),
    sheetName: `${orderId}-questionnaire`
  }
};

// Build request body for Google Sheets API
const orderData = $node['Generate OrderID'].json;

// Create the values array (headers + data row)
const values = [
  ['orderId', 'timestamp', 'companyName', 'email', 'name', 'formData'],
  [
    orderData.orderId,
    orderData.timestamp,
    orderData.companyName,
    orderData.email,
    orderData.name,
    orderData.formDataJson
  ]
];

// Build request body
const requestBody = {
  values: values
};

return {
  json: {
    spreadsheetId: $json.spreadsheetId,
    requestBody: requestBody,
    requestBodyString: JSON.stringify(requestBody)
  }
};
